// ─── Nav item type ─────────────────────────────────────────────────────────────

type NavItem = {
  label: string;
  href: string;
  icon: (props: { isDark: boolean; active: boolean }) => React.ReactNode;
  badge?: string;
  badgeColor?: string;
  badgeBg?: string;
  disabled?: boolean;
  special?: boolean; // pink card bg like "المعلم الذكي"
};

// ─── Hover-aware nav row ───────────────────────────────────────────────────────

const NavRow = ({
  item,
  active,
  isDark,
  onClose,
  locale,
}: {
  item: NavItem;
  active: boolean;
  isDark: boolean;
  onClose: () => void;
  locale: string;
}) => {
  const [hovered, setHovered] = useState(false);
  const { play } = useCoreUISound();

  const textColor = isDark ? "#F5F0FF" : "#3E256B";

  // Background logic:
  // - active: purple gradient
  // - special (المعلم الذكي): pink/rose tint, even more on hover
  // - hover (dark): white 10% overlay
  // - hover (light): lavender tint
  const getBg = () => {
    if (active) return "linear-gradient(90deg, #6948B8 0%, #8B5CF6 100%)";
    if (item.special) {
      if (isDark)
        return hovered
          ? "rgba(220, 100, 201, 0.22)"
          : "rgba(220, 100, 201, 0.14)";
      return hovered
        ? "rgba(220, 100, 201, 0.20)"
        : "rgba(220, 100, 201, 0.12)";
    }
    if (hovered && !item.disabled) {
      return isDark ? "rgba(255,255,255,0.10)" : "rgba(105, 72, 184, 0.10)";
    }
    return "transparent";
  };

  const iconColor = active ? "#FFF" : isDark ? "#D4BDFF" : "#3E256B";
  const aiIconColor = active
    ? "#FFF"
    : item.special
      ? isDark
        ? "#E89FDE"
        : "#B656C0"
      : isDark
        ? "#D4BDFF"
        : "#3E256B";

  return (
    <Link
      href={getLocalizedUrl(item.href, locale as Locale)}
      onClick={
        item.disabled
          ? (e) => e.preventDefault()
          : () => {
              play(item.special ? "ui-nav-premium" : "ui-nav-click");
              onClose();
            }
      }
      style={{ textDecoration: "none" }}
    >
      <div
        onMouseEnter={() => setHovered(true)}
        onMouseLeave={() => setHovered(false)}
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          padding: "14px 20px",
          borderRadius: "16px",
          background: getBg(),
          cursor: item.disabled ? "default" : "pointer",
          opacity: item.disabled ? (isDark ? 0.5 : 0.6) : 1,
          transform:
            hovered && !active && !item.disabled
              ? "translateX(-2px)"
              : "translateX(0)",
          transition: "background 0.18s ease, transform 0.18s ease",
        }}
      >
        {/* Right: icon + label */}
        <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
          {item.icon({ isDark, active })}
          <span
            style={{
              fontFamily: '"Readex Pro", sans-serif',
              fontSize: "18px",
              fontWeight: active ? 700 : 500,
              color: active
                ? "#FFFFFF"
                : item.special
                  ? isDark
                    ? "#E89FDE"
                    : "#B656C0"
                  : textColor,
              lineHeight: "150%",
            }}
          >
            {item.label}
          </span>
        </div>

        {/* Left: badge with lock icon */}
        {item.badge && (
          <span
            style={{
              display: "inline-flex",
              alignItems: "center",
              gap: "4px",
              fontFamily: '"Readex Pro", sans-serif',
              fontSize: "12px",
              fontWeight: 600,
              color: item.badgeColor,
              background: item.badgeBg || `${item.badgeColor}18`,
              border: `1px solid ${item.badgeColor}40`,
              borderRadius: "100px",
              padding: "3px 10px",
              whiteSpace: "nowrap",
            }}
          >
            <LockIcon color={item.badgeColor!} />
            {item.badge}
          </span>
        )}
      </div>
    </Link>
  );
};

// ─── Component ────────────────────────────────────────────────────────────────

type HomeSidebarProps = {
  open: boolean;
  onClose: () => void;
  isDark: boolean;
  onToggleDark: () => void;
};

const HomeSidebar = ({
  open,
  onClose,
  isDark,
  onToggleDark,
}: HomeSidebarProps) => {
  const { user: sessionUser, status, isLoading } = useUser();
  const session = sessionUser ? { user: sessionUser } : null;
  const { lang: locale } = useParams();
  const pathname = usePathname();
  const router = useRouter();
  const theme = useTheme();
  const { play } = useCoreUISound();

  const rawUserName = session?.user?.name || "";
  const gradeId = session?.user?.grade_id as any;
  const gradeName = getGradeName(gradeId);
  
  // Truncate name if too long (limit: 20 chars)
  const maxNameLength = 20;
  const fullName = rawUserName;
  const isNameTruncated = rawUserName.length > maxNameLength;
  const userName = isNameTruncated 
    ? rawUserName.slice(0, maxNameLength) + "..." 
    : rawUserName;

  const isActive = (href: string) => pathname?.includes(href) ?? false;

  const iconColor = isDark ? "#D4BDFF" : "#3E256B";

  const navItems: NavItem[] = [
    {
      label: "الصفحة الرئيسية",
      href: "/apps/home",
      icon: ({ active }) =>
        isDark ? (
          <HomeIconDark active={active} />
        ) : (
          <HomeIcon active={active} />
        ),
    },
    {
      label: "الرحلة التعليمية",
      href: "/apps/journey",
      icon: () => <JourneyIcon isDark={isDark} />,
    },
    {
      label: "المعلم الذكي",
      href: "/apps/chat",
      icon: ({ active }) => (
        <AITeacherIcon
          color={active ? "#FFF" : isDark ? "#E89FDE" : "#B656C0"}
        />
      ),
      badgeColor: "#B656C0",
      badgeBg: isDark ? "rgba(182,86,192,0.18)" : "rgba(182,86,192,0.12)",
      special: true,
    },
    {
      label: "الألعاب التعليمية",
      href: "/apps/games",
      icon: () => (
        <GamesIcon
          color={isDark ? "rgba(212,189,255,0.5)" : "rgba(62,37,107,0.45)"}
        />
      ),
      badge: "قريبا",
      badgeColor: "#F0A500",
      badgeBg: isDark ? "rgba(240,165,0,0.18)" : "rgba(240,165,0,0.12)",
      disabled: true,
    },
    {
      label: "الاختبارات",
      href: "/apps/quiz",
      icon: () => <ExamsIcon color={iconColor} />,
    },
    {
      label: "الإحصائيات",
      href: "/apps/statistics",
      icon: () => <StatsIcon color={iconColor} />,
    },
    {
      label: "الإعدادات",
      href: "/apps/settings",
      icon: () => <SettingsIcon color={iconColor} />,
    },
    {
      label: "الدعم والمساعدة",
      href: "/apps/support",
      icon: ({ active }) => (
        <SupportIcon color={active ? "#FFF" : isDark ? "#D4BDFF" : "#3E256B"} />
      ),
    },
  ];

  const bg = isDark ? "#2D1B69" : "#FFFFFF";
  const textColor = isDark ? "#F5F0FF" : "#3E256B";
  const dividerColor = isDark
    ? "rgba(105, 72, 184, 0.20)"
    : "rgba(105, 72, 184, 0.10)";

  const handleLogout = useCallback(async () => {
    play("ui-logout");
    await signOut({ callbackUrl: process.env.NEXT_PUBLIC_APP_URL });
  }, [play]);

  const [mounted, setMounted] = useState(false);
  useEffect(() => {
    setMounted(true);
  }, []);

  if (!open || !mounted) return null;

  return createPortal(
    <>
      {/* Backdrop */}
      <div
        onClick={onClose}
        style={{
          position: "fixed",
          inset: 0,
          backgroundColor: "rgba(0,0,0,0.4)",
          zIndex: 1200,
          backdropFilter: "blur(2px)",
        }}
        aria-hidden="true"
      />

      {/* Drawer */}
      <div
        dir="rtl"
        style={{
          position: "fixed",
          top: 0,
          right: 0,
          bottom: 0,
          width: "360px",
          maxWidth: "100vw",
          zIndex: 9999999999999,
          display: "flex",
          flexDirection: "column",
          backgroundColor: bg,
          borderRadius: "24px 0 0 24px",
          boxShadow: "-4px 0 40px rgba(0,0,0,0.18)",
          overflowY: "auto",
        }}
        role="dialog"
        aria-modal="true"
      >
        {/* ── Header ── */}
        <div
          style={{
            display: "flex",
            width: "100%",
            padding: "24px",
            justifyContent: "space-between",
            alignItems: "center",
            borderBottom: `1px solid ${dividerColor}`,
            background: isDark
              ? "linear-gradient(180deg, #3D2080 0%, #2D1B69 100%)"
              : "linear-gradient(180deg, #F8F5FF 0%, #FFF 100%)",
            boxSizing: "border-box",
          }}
        >
          {/* Right: avatar + name + grade */}
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: "12px",
              direction: "rtl",
              flex: 1,
              minWidth: 0,
              overflow: "hidden",
            }}
          >
            {status === "loading" ? (
              <UserInfoSkeleton variant="sidebar" />
            ) : (
              <>
                <div
                  style={{
                    width: "78.5px",
                    height: "78.5px",
                    borderRadius: "50%",
                    border: "4.744px solid #FFF",
                    background: session?.user?.profile_image_url
                      ? "none"
                      : "linear-gradient(180deg, #6948B8 0%, #BDA4F2 100%)",
                    boxShadow:
                      "0 2.454px 7.362px 0 rgba(0,0,0,0.10), 0 2.454px 4.908px -2.454px rgba(0,0,0,0.10)",
                    display: "flex",
                    alignItems: session?.user?.profile_image_url
                      ? "center"
                      : "flex-end",
                    justifyContent: "center",
                    fontSize: "36px",
                    overflow: "hidden",
                    flexShrink: 0,
                  }}
                >
                  {session?.user?.profile_image_url ? (
                    <img
                      src={session.user.profile_image_url}
                      alt={userName}
                      style={{
                        width: "100%",
                        height: "100%",
                        objectFit: "cover",
                      }}
                    />
                  ) : (
                    "👦"
                  )}
                </div>
                <div style={{ textAlign: "right", minWidth: 0, overflow: "hidden" }}>
                  <p
                    style={{
                      fontFamily: '"Readex Pro", sans-serif',
                      fontSize: "18px",
                      fontWeight: 700,
                      color: isDark ? "#F5F0FF" : "#3E256B",
                      margin: 0,
                      lineHeight: "150%",
                      maxWidth: "180px",
                      overflow: "hidden",
                      textOverflow: "ellipsis",
                      whiteSpace: "nowrap",
                    }}
                    title={fullName}
                  >
                    {userName}
                  </p>
                  <p
                    style={{
                      fontFamily: '"Readex Pro", sans-serif',
                      fontSize: "15px",
                      fontWeight: 400,
                      color: "#DC64C9",
                      margin: 0,
                      lineHeight: "150%",
                    }}
                  >
                    {gradeName}
                  </p>
                </div>
              </>
            )}
          </div>

          {/* Left: close + mode toggle */}
          <div
            style={{
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              gap: "12px",
            }}
          >
            {/* Close button */}
            <button
              onClick={onClose}
              aria-label="Close menu"
              style={{
                cursor: "pointer",
                display: "flex",
                width: "40px",
                height: "40px",
                justifyContent: "center",
                alignItems: "center",
                borderRadius: "12px",
                background: isDark ? "rgba(255,255,255,0.12)" : "#FFF",
                border: "none",
                boxShadow: "0 2px 6px 0 rgba(0, 0, 0, 0.08)",
              }}
            >
              <svg
                xmlns="http://www.w3.org/2000/svg"
                width="20"
                height="20"
                viewBox="0 0 20 20"
                fill="none"
              >
                <path
                  d="M14.9998 5L4.99976 15"
                  stroke={isDark ? "#F5F0FF" : "#3E256B"}
                  strokeWidth="1.66667"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
                <path
                  d="M4.99976 5L14.9998 15"
                  stroke={isDark ? "#F5F0FF" : "#3E256B"}
                  strokeWidth="1.66667"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
              </svg>
            </button>

            {/* Mode toggle */}
            <button
              onClick={() => {
                play("ui-theme-toggle");
                onToggleDark();
              }}
              aria-label="Toggle dark mode"
              style={{
                width: "40px",
                height: "40px",
                borderRadius: "12px",
                background: "#6948B8",
                border: "none",
                cursor: "pointer",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                transition: "background 0.2s",
              }}
            >
              {isDark ? (
                <svg
                  width="22"
                  height="22"
                  viewBox="0 0 24 24"
                  fill="none"
                  aria-hidden="true"
                >
                  <circle
                    cx="12"
                    cy="12"
                    r="5"
                    fill="#F5F0FF"
                  />
                  <path
                    d="M12 2v2M12 20v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M2 12h2M20 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42"
                    stroke="#F5F0FF"
                    strokeWidth="2"
                    strokeLinecap="round"
                  />
                </svg>
              ) : (
                <svg
                  width="22"
                  height="22"
                  viewBox="0 0 24 24"
                  fill="none"
                  aria-hidden="true"
                >
                  <path
                    d="M21 12.79A9 9 0 1111.21 3 7 7 0 0021 12.79z"
                    fill="#FFFFFF"
                  />
                </svg>
              )}
            </button>
          </div>
        </div>

        {/* ── Nav items ── */}
        <nav
          style={{
            flex: 1,
            padding: "34px 24px",
            display: "flex",
            flexDirection: "column",
            gap: "16px",
          }}
        >
          {navItems.map((item) => (
            <NavRow
              key={item.href}
              item={item}
              active={isActive(item.href)}
              isDark={isDark}
              onClose={onClose}
              locale={locale as string}
            />
          ))}
        </nav>

        {/* ── Logout ── */}
        <div
          style={{
            padding: "8px 24px 32px",
            borderTop: isDark
              ? "1px solid rgba(255,255,255,0.08)"
              : "1px solid rgba(105,72,184,0.12)",
          }}
        >
          <button
            onClick={handleLogout}
            style={{
              width: "100%",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              gap: "10px",
              padding: "16px 24px",
              borderRadius: "16px",
              background: isDark
                ? "rgba(251, 44, 54, 0.12)"
                : "rgba(251, 44, 54, 0.08)",
              border: "none",
              cursor: "pointer",
              fontFamily: '"Readex Pro", sans-serif',
              fontSize: "18px",
              fontWeight: 700,
              color: "#FB2C36",
              lineHeight: "150%",
              direction: "rtl",
              transition: "background 0.2s",
            }}
          >
            <LogoutIcon />
            تسجيل الخروج
          </button>
        </div>
      </div>
    </>,
    document.body
  );
};

export default HomeSidebar;
